            const totalRows = state.modal?.querySelectorAll?.('#tmTaskTable tbody tr[data-id], #tmTimelineLeftTable tbody tr[data-id]')?.length || 0;
            if (totalFiltered > 220 || totalRows > 320) return 'none';
